prompt.format:
{{
    "patterns": [
        {{
            "id": "unique_pattern_identifier",
            "type": "temporal|cross_source|entity_related|sentiment|frequency|anomaly",
            "category": "risk|opportunity|trend|relationship|communication|workflow",
            "title": "Brief descriptive title",
            "description": "Detailed description of the pattern",
            "evidence": [
                "Specific examples or quotes supporting this pattern"
            ],
            "frequency": 5,
            "confidence_score": 0.85,
            "novelty_score": 0.72,
            "severity": "low|medium|high",
            "timeframe": "when this pattern was observed",
            "entities_involved": ["person_id", "project_id", "team_id"],
            "sources": ["meetings", "commits", "documents"],
            "implications": [
                "What this pattern suggests or predicts"
            ],
            "recommendations": [
                "Actionable steps based on this pattern"
            ],
            "related_patterns": ["pattern_id_1", "pattern_id_2"]
        }}
    ],
    "pattern_summary": {{
        "total_patterns": 10,
        "high_confidence_patterns": 7,
        "novel_insights": 4,
        "risk_patterns": 2,
        "opportunity_patterns": 3,
        "trend_patterns": 5,
        "cross_source_correlations": 3,
        "anomalies_detected": 1
    }},
    "insights": [
        "High-level insights derived from pattern analysis"
    ],
    "predictions": [
        {{
            "prediction": "What is likely to happen",
            "confidence": 0.8,
            "timeframe": "when it might happen",
            "supporting_patterns": ["pattern_id_1", "pattern_id_2"]
        }}
    ]
}}
